if (!document.getElementById('feed-font')) {
  const style = document.createElement('style');
  style.id = 'feed-font';
  style.textContent = "@font-face { font-family: 'GlassTTY'; src: url('/public/fonts/Glass_TTY_VT220.ttf') format('truetype'); }";
  document.head.appendChild(style);
}

if (!document.fonts.check('20px GlassTTY')) {
  document.fonts.load('20px GlassTTY').catch(() => {});
  return {
    backgroundColor: '#181b1f',
    animation: false,
    graphic: [{ type: 'group', $action: 'replace', children: [{
      type: 'text', left: 'center', top: 'center',
      style: { text: 'Loading font...', fill: '#666', fontSize: 16 }
    }] }],
    series: []
  };
}

const TAG_COLORS = {
  'GOAL': [255, 200,  60],
  'THNK': [140, 170, 130],
  'DONE': [  0, 102,   0],
  'READ': [  0,   0, 255],
  'EDIT': [128, 128,   0],
  'GREP': [120, 140, 200],
  'ACT':  [230, 150,  50],
  'EXEC': [180, 160,  60],
  'TEAM': [180, 120, 220],
  'COMM': [150, 140, 210],
  'TASK': [240, 110, 170],
  'WEB':  [210, 130, 180],
  'ASK':  [255, 100, 100],
  'PLAN': [160, 160, 220],
  'TOOL': [160, 160, 160],
  'WARN': [255, 160,  40],
};

const FONT = "'GlassTTY', 'Roboto Mono', 'Consolas', monospace";
const FONT_SIZE = 20;
const LINE_H = 22;
const PAD_LEFT = 8;
const PAD_TOP = 8;

function tagColor(tag) {
  const t = (tag || '').trim();
  return TAG_COLORS[t] || TAG_COLORS['TOOL'];
}

function rgb(c) { return 'rgb(' + c[0] + ',' + c[1] + ',' + c[2] + ')'; }

function simpleHash(str) {
  let h0 = 0x811c9dc5, h1 = 0x01000193, h2 = 0xdeadbeef;
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    h0 = ((h0 ^ c) * 0x01000193) >>> 0;
    h1 = ((h1 ^ c) * 0x811c9dc5) >>> 0;
    h2 = ((h2 ^ c) * 0x1b873593) >>> 0;
  }
  return [(h0 >>> 24) & 0xff, (h1 >>> 24) & 0xff, (h2 >>> 24) & 0xff];
}

function entityColor(name, salt) {
  const bytes = simpleHash((salt || '') + (name || ''));
  let ch = [
    60 + (bytes[0] * 150 / 255),
    60 + (bytes[1] * 150 / 255),
    60 + (bytes[2] * 150 / 255)
  ];
  let mx = 0, mn = 0;
  for (let i = 1; i < 3; i++) {
    if (ch[i] > ch[mx]) mx = i;
    if (ch[i] < ch[mn]) mn = i;
  }
  ch[mx] = Math.min(ch[mx] + 40, 230);
  ch[mn] = Math.max(ch[mn] - 30, 40);
  return 'rgb(' + Math.round(ch[0]) + ',' + Math.round(ch[1]) + ',' + Math.round(ch[2]) + ')';
}

function padTag(tag) {
  const t = (tag || '').trim();
  if (t.length >= 4) return t.substring(0, 4);
  return (' '.repeat(4 - t.length)) + t;
}

function mkStyle(fill) {
  return { fontFamily: FONT, fontSize: FONT_SIZE, fill: fill };
}

function truncLine(s) {
  let line = (s || '').replace(/\r?\n/g, ' ').replace(/[\r\x00-\x1f]/g, '');
  if (line.length > 120) line = line.substring(0, 117) + '...';
  return line;
}

function renderDisplay(display, tagColorStr, stylePrefix) {
  const line = truncLine(display || '');
  const parts = line.split(/__([^_]+)__/g);
  const rich = {};
  let text = '';
  for (let j = 0; j < parts.length; j++) {
    let part = parts[j];
    const key = stylePrefix + '_' + j;
    if (j % 2 === 1) {
      if (j > 0 && parts[j-1].endsWith(' ')) {
        part = ' ' + part;
      }
      rich[key] = { fontFamily: FONT, fontSize: FONT_SIZE, fill: 'rgb(0,255,255)' };
    } else {
      if (j < parts.length - 1 && part.endsWith(' ')) {
        part = part.slice(0, -1);
      }
      rich[key] = { fontFamily: FONT, fontSize: FONT_SIZE, fill: tagColorStr };
    }
    text += '{' + key + '|' + part + '}';
  }
  return { text, rich };
}

const s = context.panel.data.series[0];
if (!s || !s.fields || s.fields.length === 0) {
  return {
    backgroundColor: '#181b1f',
    animation: false,
    graphic: [{ type: 'group', $action: 'replace', children: [{
      type: 'text', left: 'center', top: 'center',
      style: { text: 'No data', fill: '#888', fontFamily: FONT, fontSize: 16 }
    }] }],
    series: []
  };
}

const field = (name) => {
  const f = s.fields.find(x => x.name === name);
  if (!f) return [];
  return f.values.buffer || f.values;
};

const tsArr = field('ts');
const sessionArr = field('session');
const agentArr = field('agent_name');
const tagArr = field('tag');
const displayArr = field('display');
const teamArr = field('team');
const focusArr = field('focus');
const bashArr = field('bash_cmd');
const warnArr = field('warn_msg');

const len = tsArr.length || 0;

let maxSession = 'session/team'.length;
let maxAgent = 'agent'.length;
for (let i = 0; i < len; i++) {
  const session = sessionArr[i] || '';
  const team = (teamArr.length > i) ? (teamArr[i] || '') : '';
  const agent = (agentArr[i] || '') || '@lead';
  const sl = team ? ('#' + team).length : Math.min(session.length, 8);
  const al = (agent.startsWith('@') ? agent : '@' + agent).length;
  if (sl > maxSession) maxSession = sl;
  if (al > maxAgent) maxAgent = al;
}

const elements = [];
let row = 0;

const hrich = {};
hrich.ht = { fontFamily: FONT, fontSize: FONT_SIZE, fill: '#ffffff', fontWeight: 'bold' };
elements.push({
  type: 'text',
  left: 0,
  top: PAD_TOP,
  style: {
    text: '{ht|' + 'HH:MM:SS' + ' }{ht|' + 'session/team'.padEnd(maxSession) + ' }{ht|' + 'agent'.padEnd(maxAgent) + ' }{ht|' + '[' + 'tag'.padEnd(4) + ']' + ' }{ht|display}',
    rich: hrich,
    backgroundColor: '#0000aa',
    width: 2000,
    padding: [2, PAD_LEFT, 2, PAD_LEFT]
  }
});
row = 1;

for (let i = 0; i < len; i++) {
  const ts = tsArr[i] || '';
  const session = sessionArr[i] || '';
  const agent = agentArr[i] || '@lead';
  const tag = (tagArr[i] || '').trim();
  const display = displayArr[i] || '';
  const team = (teamArr.length > i) ? (teamArr[i] || '') : '';
  const focus = (focusArr.length > i) ? (focusArr[i] || '') : '';
  const bash = (bashArr.length > i) ? (bashArr[i] || '') : '';
  const warn = (warnArr.length > i) ? (warnArr[i] || '') : '';

  if (!tag && !focus && !bash && !warn) continue;

  let timePart = '';
  try {
    const d = new Date(ts);
    timePart = d.toLocaleTimeString('en-GB', {hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false});
  } catch(e) { timePart = (ts || '').substring(11,19) || '??:??:??'; }

  const sessionLabel = team ? '#' + team : (session.length > 8 ? session.substring(0,8) : session);
  const sessionColor = entityColor(sessionLabel, session);
  const agentLabel = agent.startsWith('@') ? agent : '@' + agent;
  const agentColor = entityColor(agentLabel, session);

  let tc = tagColor(tag);
  let tagDisplay = tag;
  let lineDisplay = display;
  if (warn) { tagDisplay = 'WARN'; lineDisplay = warn; tc = TAG_COLORS['WARN']; }
  if (focus && !tag) { tagDisplay = 'GOAL'; lineDisplay = focus; tc = TAG_COLORS['GOAL']; }

  const pt = padTag(tagDisplay);
  const ri = 'r' + row;
  const rich = {};
  rich['t' + ri] = mkStyle('#666');
  rich['s' + ri] = mkStyle(sessionColor);
  rich['a' + ri] = mkStyle(agentColor);
  rich['g' + ri] = mkStyle(rgb(tc));

  const disp = renderDisplay(lineDisplay, rgb(tc), 'd' + ri);
  Object.assign(rich, disp.rich);

  const lineText = '{t' + ri + '|' + timePart + ' }{s' + ri + '|' + sessionLabel.padEnd(maxSession) + ' }{a' + ri + '|' + agentLabel.padEnd(maxAgent) + ' }{g' + ri + '|[' + pt + '] }' + disp.text;

  elements.push({
    type: 'text',
    left: PAD_LEFT,
    top: PAD_TOP + row * LINE_H,
    style: { text: lineText, rich: rich }
  });
  row++;

  if (bash) {
    const bi = 'r' + row;
    const brich = {};
    brich['t' + bi] = mkStyle('#666');
    brich['s' + bi] = mkStyle(sessionColor);
    brich['a' + bi] = mkStyle(agentColor);
    brich['g' + bi] = mkStyle(rgb(TAG_COLORS['EXEC']));
    brich['d' + bi] = mkStyle('rgb(120,120,100)');

    const bashText = '{t' + bi + '|' + timePart + ' }{s' + bi + '|' + sessionLabel.padEnd(maxSession) + ' }{a' + bi + '|' + agentLabel.padEnd(maxAgent) + ' }{g' + bi + '|[EXEC] }{d' + bi + '|' + truncLine(bash) + '}';
    elements.push({ type: 'text', left: PAD_LEFT, top: PAD_TOP + row * LINE_H, style: { text: bashText, rich: brich } });
    row++;
  }

  if (focus && tag) {
    const fi = 'r' + row;
    const frich = {};
    frich['t' + fi] = mkStyle('#666');
    frich['s' + fi] = mkStyle(sessionColor);
    frich['a' + fi] = mkStyle(agentColor);
    frich['g' + fi] = mkStyle(rgb(TAG_COLORS['GOAL']));

    const fdisp = renderDisplay(focus, rgb(TAG_COLORS['GOAL']), 'd' + fi);
    Object.assign(frich, fdisp.rich);

    const focusText = '{t' + fi + '|' + timePart + ' }{s' + fi + '|' + sessionLabel.padEnd(maxSession) + ' }{a' + fi + '|' + agentLabel.padEnd(maxAgent) + ' }{g' + fi + '|[GOAL] }' + fdisp.text;

    elements.push({
      type: 'text',
      left: PAD_LEFT,
      top: PAD_TOP + row * LINE_H,
      style: { text: focusText, rich: frich }
    });
    row++;
  }
}

if (elements.length <= 1) {
  elements.push({
    type: 'text', left: 'center', top: 'center',
    style: { text: 'No displayable events', fill: '#888', fontFamily: FONT, fontSize: 14 }
  });
}

return {
  backgroundColor: '#181b1f',
  animation: false,
  graphic: [{ type: 'group', $action: 'replace', children: elements }],
  series: []
};
